@* Displays a single task card with move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeftClicked" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRightClicked" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private bool IsMoving;

    private async System.Threading.Tasks.Task OnMoveLeftClicked()
    {
        IsMoving = true;
        await OnMoveLeft.InvokeAsync(Task);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRightClicked()
    {
        IsMoving = true;
        await OnMoveRight.InvokeAsync(Task);
        IsMoving = false;
    }
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="form-field">
        <label>Title</label>
        <input type="text" @bind="Title" placeholder="Task title" />
    </div>
    <div class="form-field">
        <label>Assignee</label>
        <input type="text" @bind="Assignee" placeholder="Assignee name" />
    </div>
    <div class="form-field">
        <label>Priority</label>
        <select @bind="Priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-field">
        <label>Due Date</label>
        <input type="date" @bind="DueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@IsSaving">Save</button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@IsSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="form-error">@ErrorMessage</div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = string.Empty;
    private string Assignee { get; set; } = string.Empty;
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving;
    private string? ErrorMessage;

    private async Task HandleSave()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Assignee))
        {
            ErrorMessage = "Assignee is required.";
            return;
        }

        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;

        // Reset form
        Title = string.Empty;
        Assignee = string.Empty;
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column with header, task cards, and add-task button/form *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnAddTask.InvokeAsync(newTask);
        showAddForm = false;
    }

    private void HandleCancel()
    {
        showAddForm = false;
    }
}

@* Search input for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}

