@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<div class="board-page">
    <h2>Kanban Board</h2>

    @if (isLoading)
    {
        <div class="board-loading">Loading tasks…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="board-error">
            <p>@errorMessage</p>
            <button @onclick="LoadTasks">Retry</button>
        </div>
    }
    else
    {
        <BoardSummaryBar TotalCount="allTasks.Count"
                         ToDoCount="ToDo.Count"
                         InProgressCount="InProgress.Count"
                         DoneCount="Done.Count"
                         OverdueCount="OverdueCount" />

        <BoardSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />

        <div class="board-columns">
            <BoardColumn ColumnName="To Do"
                         Tasks="FilteredToDo"
                         ShowMoveLeft="false"
                         ShowMoveRight="true"
                         OnMoveRight="task => MoveTask(task, &quot;In Progress&quot;)"
                         OnAddTask="args => AddTask(args, &quot;To Do&quot;)" />

            <BoardColumn ColumnName="In Progress"
                         Tasks="FilteredInProgress"
                         ShowMoveLeft="true"
                         ShowMoveRight="true"
                         OnMoveLeft="task => MoveTask(task, &quot;To Do&quot;)"
                         OnMoveRight="task => MoveTask(task, &quot;Done&quot;)"
