@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<div class="board-page">
    <h2>Kanban Board</h2>

    @if (isLoading)
    {
        <div class="board-loading">Loading tasks…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="board-error">
            <p>@errorMessage</p>
            <button @onclick="LoadTasks">Retry</button>
        </div>
    }
    else
    {
        <BoardSummaryBar TotalCount="allTasks.Count"
                         ToDoCount="ToDo.Count"
                         InProgressCount="InProgress.Count"
                         DoneCount="Done.Count"
                         OverdueCount="OverdueCount" />

        <BoardSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />

        <div class="board-columns">
            <BoardColumn ColumnName="To Do"
                         Tasks="FilteredToDo"
                         ShowMoveLeft="false"
                         ShowMoveRight="true"
                         OnMoveRight="task => MoveTask(task, &quot;In Progress&quot;)"
                         OnAddTask="args => AddTask(args, &quot;To Do&quot;)" />

            <BoardColumn ColumnName="In Progress"
                         Tasks="FilteredInProgress"
                         ShowMoveLeft="true"
                         ShowMoveRight="true"
                         OnMoveLeft="task => MoveTask(task, &quot;To Do&quot;)"
                         OnMoveRight="task => MoveTask(task, &quot;Done&quot;)"
                         OnAddTask="args => AddTask(args, &quot;In Progress&quot;)" />

            <BoardColumn ColumnName="Done"
                         Tasks="FilteredDone"
                         ShowMoveLeft="true"
                         ShowMoveRight="false"
                         OnMoveLeft="task => MoveTask(task, &quot;In Progress&quot;)"
                         OnAddTask="args => AddTask(args, &quot;Done&quot;)" />
        </div>
    }
</div>

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists by status
    private List<TaskItem> ToDo => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgress => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> Done => allTasks.Where(t => t.Status == "Done").ToList();

    // Filtered lists (client-side search)
    private List<TaskItem> FilteredToDo => ApplySearch(ToDo);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgress);
    private List<TaskItem> FilteredDone => ApplySearch(Done);

    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update the local list to reflect the change
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service returns a task; ensure it has the correct status column
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

